// Generated by Claude Sonnet 4.6

import { createReducer } from '@reduxjs/toolkit';

import {
  kubeconfigRefreshErrorAction,
  kubeconfigRefreshRequestAction,
  kubeconfigRefreshSuccessAction,
} from '@/store/Kubeconfig/actions';

export type KubeconfigState = {
  isLoading: boolean;
  error: string | undefined;
};

export const unloadedState: KubeconfigState = {
  isLoading: false,
  error: undefined,
};

export const reducer = createReducer(unloadedState, builder =>
  builder
    .addCase(kubeconfigRefreshRequestAction, state => {
      state.isLoading = true;
      state.error = undefined;
    })
    .addCase(kubeconfigRefreshSuccessAction, state => {
      state.isLoading = false;
    })
    .addCase(kubeconfigRefreshErrorAction, (state, action) => {
      state.isLoading = false;
      state.error = action.payload;
    })
    .addDefaultCase(state => state),
);
